',{id:"state_pension_funding_ratio_map",title:"State pension funding ratio 2024 - which states are building a retirement time bomb",sub:"Wisconsin: 104% funded - the only fully funded major state pension. New Jersey: 38% funded. Illinois: 44%. Kentucky: 51%. The unfunded pension liability is $1.4 trillion nationally. States with underfunded pensions face either tax increases, benefit cuts, or both within 15 years.",type:"MAP",geo:"us_state",fmt:"State choropleth",tbl:"Pew Charitable Trusts state pension funding data 2024 (public)",section:"State Government",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by state (bls.gov - free)"],vars:["state_local_debt_per_capita","state_local_expenditure_per_capita"],join:["median_household_income","rep_pct","population_pct_change"],sc:{emotional:8,relatability:7,surprise:8,tension:8,visual:7,data_ready:9,originality:5},vs:75,tags:"state pension funding ratio 2024 Wisconsin 104% New Jersey 38% Illinois 44% Kentucky 51% $1.4 trillion unfunded time bomb tax benefit cuts Pew Charitable"}',
',{id:"state_income_tax_rate_vs_migration",title:"State top income tax rate vs. net domestic migration 2019-2024 - do taxes drive people to leave?",sub:"California: 13.3% top rate, net outmigration of 800K 2019-2024. Florida: 0% income tax, net inmigration of 1.4M. Texas: 0%, +900K. But Washington state: 0% income tax and still losing population. The tax-migration link is real but overstated - housing costs explain more.",type:"XREF",geo:"us_state",fmt:"Scatter plot",tbl:"Tax Foundation state income tax rates + IRS migration data 2019-2024 (public)",section:"State Government",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by state (bls.gov - free)"],vars:["state_income_tax_revenue","irs_net_migration_households"],join:["home_price_index_2024","median_household_income","housing_permits_total"],sc:{emotional:7,relatability:8,surprise:8,tension:5,visual:6,data_ready:9,originality:7},vs:72,tags:"state income tax rate migration 2019 2024 California 13.3% -800K Florida 0% +1.4M Texas +900K Washington 0% losing housing costs explain overstated Tax Foundation IRS"}',
',{id:"state_housing_permits_per_capita",title:"Housing permits issued per 1,000 residents by state 2023-2024 - who is actually building",sub:"South Carolina: 12.4 permits per 1,000 residents - the highest build rate. Idaho: 11.8. Utah: 11.3. California: 2.1. New York: 1.9. The housing permit map directly explains rent trends - states building the most have the lowest rent growth. Supply is the variable.",type:"MAP",geo:"us_state",fmt:"State choropleth",tbl:"Census Bureau residential construction permits by state (public, monthly)",section:"Housing",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by state (bls.gov - free)"],vars:["housing_permits_total","home_price_pct_change_2005_2024"],join:["median_household_income","population_pct_change","housing_cpi"],sc:{emotional:7,relatability:8,surprise:7,tension:6,visual:7,data_ready:10,originality:5},vs:70,tags:"housing permits per 1000 residents state South Carolina 12.4 Idaho 11.8 Utah 11.3 California 2.1 New York 1.9 rent growth supply variable Census Bureau"}',
