',{id:"state_gig_worker_share_by_industry",title:"Gig and contract worker share by state and industry - the geography of labor market fragmentation",sub:"California: 34% of workers classified as independent contractors or gig workers - the highest in the US. Mississippi: 18%. The gig geography follows the platform economy: high-income coastal states where apps are most embedded have the most workers without benefits.",type:"MAP",geo:"us_state",fmt:"State choropleth",tbl:"BLS Contingent Worker Supplement + DOL contractor classification data (public)",section:"Labor Force",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by state (bls.gov - free)"],vars:["gig_transport_receipts","female_lfp_rate"],join:["median_household_income","pct_bachelors","state_unemployment_rate"],sc:{emotional:7,relatability:7,surprise:7,tension:6,visual:6,data_ready:7,originality:6},vs:65,tags:"gig contract worker share state industry California 34% Mississippi 18% platform economy apps benefits coastal BLS Contingent Worker DOL contractor"}',
',{id:"state_uninsured_rate_post_aca",title:"Uninsured rate by state 2024 - the ACA coverage map after 14 years",sub:"Texas: 18.4% uninsured - the highest in the nation. Oklahoma: 14.2%. Wyoming: 12.1%. Massachusetts: 2.8%. Vermont: 2.3%. The uninsured map directly overlaps with states that refused Medicaid expansion. 14 years after ACA, the gap has not closed.",type:"MAP",geo:"us_state",fmt:"State choropleth",tbl:"ACS health insurance coverage by state 2024 (Census API - free tidycensus)",section:"Health",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by state (bls.gov - free)"],vars:["uninsured_rate","pct_on_medicaid"],join:["median_household_income","rep_pct","rural_population_pct"],sc:{emotional:8,relatability:8,surprise:6,tension:7,visual:7,data_ready:10,originality:4},vs:73,tags:"uninsured rate state 2024 Texas 18.4% Oklahoma Wyoming Massachusetts 2.8% Vermont ACA Medicaid expansion refused 14 years gap not closed ACS Census"}',
',{id:"xref_state_education_spending_vs_outcomes",title:"Per-pupil education spending vs. NAEP test scores by state - does money matter?",sub:"New York: $24,881 per pupil. 8th grade math NAEP: 282. Utah: $8,014 per pupil. NAEP: 291. The spending-outcome correlation is 0.18 - weak. Massachusetts spends $18K and scores 305. Mississippi spends $9K and scores 262. The money matters but the system it flows into matters more.",type:"XREF",geo:"us_state",fmt:"Scatter plot",tbl:"NCES per-pupil spending by state + NAEP State Report Cards (both public)",section:"Education",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by state (bls.gov - free)"],vars:["expenditure_per_pupil","pct_hs_grad"],join:["median_household_income","rep_pct","pct_bachelors"],sc:{emotional:7,relatability:8,surprise:8,tension:5,visual:5,data_ready:10,originality:6},vs:71,tags:"per-pupil spending NAEP test scores state New York $24881 282 Utah $8014 291 correlation 0.18 Massachusetts $18K 305 Mississippi $9K 262 money system NCES"}',
',{id:"state_corporate_tax_rate_vs_job_growth",title:"State corporate tax rate vs. private sector job growth 2015-2024 - do low taxes create jobs?",sub:"Florida: 5.5% corporate rate, 28% private sector job growth. Texas: 0% corporate tax, 24% job growth. But Nevada: 0% corporate rate, 21% growth. Connecticut: 7.5%, 11% growth. The correlation between corporate tax rates and job growth is 0.04 - essentially zero.",type:"XREF",geo:"us_state",fmt:"Scatter plot",tbl:"Tax Foundation state corporate tax data + BLS QCEW state job growth 2015-2024",section:"State Government",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by state (bls.gov - free)"],vars:["state_income_tax_revenue","state_local_revenue_per_capita"],join:["median_household_income","rep_pct","manufacturing_employment_trend"],sc:{emotional:8,relatability:6,surprise:9,tension:7,visual:5,data_ready:9,originality:7},vs:75,tags:"corporate tax rate job growth state Florida 5.5% 28% Texas 0% 24% Nevada 0% 21% Connecticut 7.5% 11% correlation 0.04 zero Tax Foundation BLS QCEW"}',
