',{id:"state_prison_cost_per_inmate",title:"Annual cost to incarcerate one person by state 2024 - what prison actually costs",sub:"New York: $400,000 per inmate per year - the most expensive prison system in the US. California: $132,000. Louisiana: $26,000 (least expensive but among worst outcomes). The per-inmate cost map reveals that the states spending the most on prisons are not getting proportionally better outcomes.",type:"MAP",geo:"us_state",fmt:"State choropleth",tbl:"Vera Institute of Justice prison cost data 2024 (public)",section:"Law Enforcement",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by state (bls.gov - free)"],vars:["violent_crime_rate","murder_rate"],join:["rep_pct","median_household_income","pct_bachelors"],sc:{emotional:8,relatability:7,surprise:8,tension:6,visual:7,data_ready:8,originality:7},vs:74,tags:"prison cost per inmate state 2024 New York $400K California $132K Louisiana $26K most expensive worst outcomes spending proportional Vera Institute"}',
',{id:"state_opioid_settlement_spending_map",title:"Opioid settlement money by state - $50 billion and what happened to it",sub:"The national opioid settlement totals $50B+ from Purdue Pharma, J&J, and distributors. West Virginia: $1,300 per resident. Ohio: $890. But 40% of settlement funds have been diverted to state general funds unrelated to addiction treatment. The settlement map and the treatment investment map are different.",type:"MAP",geo:"us_state",fmt:"State choropleth",tbl:"KFF opioid settlement tracker + state appropriations data (public)",section:"Health",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by state (bls.gov - free)"],vars:["per_capita_health_spending","rural_population_pct"],join:["median_household_income","rep_pct","pct_on_medicaid"],sc:{emotional:9,relatability:7,surprise:8,tension:8,visual:7,data_ready:7,originality:8},vs:79,tags:"opioid settlement money state $50B Purdue Pharma J&J West Virginia $1300 Ohio $890 40% diverted general funds treatment map different KFF tracker"}',
',{id:"state_electric_utility_rate_by_state",title:"Residential electricity price per kWh by state 2024 - who pays the most to keep the lights on",sub:"Hawaii: 39.8 cents per kWh - nearly 4x the national average. Louisiana: 10.3 cents. The electricity price map reflects a state energy mix, regulation model, and infrastructure age. Hawaii is expensive because it burns imported oil. Louisiana is cheap because it sits on natural gas.",type:"MAP",geo:"us_state",fmt:"State choropleth",tbl:"EIA Electric Power Monthly state residential rates (public monthly)",section:"Energy",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","EIA State Energy Data System: production + consumption by state (eia.gov - free API)"],vars:["energy_consumption_per_capita","renewable_energy_share"],join:["median_household_income","gasoline_cpi","coal_consumption"],sc:{emotional:6,relatability:9,surprise:7,tension:4,visual:7,data_ready:10,originality:5},vs:68,tags:"electricity price per kWh state 2024 Hawaii 39.8 cents Louisiana 10.3 4x national average oil gas regulation infrastructure age EIA Electric Power Monthly"}',
',{id:"xref_state_gun_laws_vs_gun_deaths",title:"State gun law strength index vs. gun death rate - the clearest policy-outcome relationship in public health",sub:"Hawaii: gun law score 82/100, gun death rate 3.4 per 100K. Mississippi: score 4/100, death rate 28.6 per 100K. The correlation is -0.82 - among the strongest policy-outcome correlations in US public health data. The map of gun laws and the map of gun deaths are nearly a perfect inverse.",type:"XREF",geo:"us_state",fmt:"Scatter plot",tbl:"Giffords Law Center state gun law scorecard + CDC gun death data by state (both public)",section:"Law Enforcement",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by state (bls.gov - free)"],vars:["violent_crime_rate","murder_rate"],join:["rep_pct","rural_population_pct","median_household_income"],sc:{emotional:9,relatability:8,surprise:8,tension:9,visual:6,data_ready:9,originality:5},vs:83,tags:"gun law strength gun death rate state Hawaii 82/100 3.4 per 100K Mississippi 4/100 28.6 correlation -0.82 strongest policy outcome Giffords CDC inverse perfect"}',
',{id:"state_renewable_jobs_vs_fossil_fuel_jobs",title:"Renewable energy jobs vs. fossil fuel jobs by state 2024 - the energy employment transition",sub:"Texas: 271K fossil fuel jobs vs. 238K clean energy jobs - the transition is nearly at parity in the biggest oil state. California: 37K fossil vs. 594K clean. Wyoming: 8.4K fossil vs. 3.1K clean - the most fossil-dependent state per capita with the weakest transition.",type:"MAP",geo:"us_state",fmt:"State choropleth",tbl:"DOE US Energy and Employment Report 2024 (public annual)",section:"Energy",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","EIA State Energy Data System: production + consumption by state (eia.gov - free API)"],vars:["renewable_energy_share","coal_production_index"],join:["oil_gas_extraction_index","manufacturing_employment_trend","rep_pct"],sc:{emotional:7,relatability:7,surprise:8,tension:7,visual:7,data_ready:8,originality:7},vs:72,tags:"renewable jobs fossil fuel jobs state 2024 Texas 271K fossil 238K clean parity California 37K fossil 594K clean Wyoming 8.4K 3.1K DOE US Energy Employment"}',
',{id:"state_child_poverty_rate_trends",title:"Child poverty rate by state 2019 vs. 2024 - the COVID policy experiment revealed",sub:"In 2021, the Child Tax Credit expansion cut child poverty from 14.4% to 5.2% - the single largest one-year poverty reduction in US history. When it expired in 2022, child poverty rose back to 12.4% in one year. The state-by-state data shows exactly which states recovered and which didn\'t.",type:"MAP",geo:"us_state",fmt:"State choropleth",tbl:"ACS child poverty by state 2019-2024 + Columbia Center CPSP estimates (public)",section:"Income",ext:["ACS 5-year estimates: MHI, poverty rate, population by geography (Census API - free, tidycensus)","BEA Regional: GDP + personal income per capita by state (apps.bea.gov - free)","Census Population Estimates: annual population by state/county (census.gov - free)","BLS LAUS: unemployment + labor force by state (bls.gov - free)"],vars:["pct_on_snap","pct_under_25k"],join:["median_household_income","birth_rate_state","rep_pct"],sc:{emotional:10,relatability:8,surprise:9,tension:8,visual:7,data_ready:9,originality:7},vs:87,tags:"child poverty rate state 2019 2024 CTC 14.4% 5.2% largest one-year reduction history expired 2022 12.4% one year state recovered ACS Columbia CPSP experiment"}'
